blocks.body:
{
    "level": "A1–B1",
    "intro": "W tym temacie nauczysz się <strong>pytań specjalnych (pytań „Wh”)</strong> – pytań rozpoczynających się od słów pytających i wymagaj w odpowiedzi konkretnych informacji.",
    "rules": [
        {
            "label": "KTO/CO",
            "color": "emerald",
            "text": "<strong>Kto? Co?</strong> – pytania o ludzi i rzeczy:",
            "example": "Kim ona jest? Czego chcesz?"
        },
        {
            "label": "GDZIE / KIEDY",
            "color": "blue",
            "text": "<strong>Gdzie? Kiedy?</strong> – pytania o miejsce i czas:",
            "example": "Gdzie mieszkasz? Kiedy to się zaczyna?"
        },
        {
            "label": "DLACZEGO/JAK",
            "color": "amber",
            "text": "<strong>Dlaczego? Jak?</strong> – pytanie o przyczynę i metodę:",
            "example": "Dlaczego się spóźniasz? Jak to działa?"
        }
    ]
}

{
    "title": "1. Co to są pytania Wh?",
    "intro": "Pytania Wh (pytania specjalne) to pytania zawierające słowa pytające, które wymagają szczegółowej odpowiedzi:",
    "items": [
        {
            "label": "Pytanie ogólne",
            "title": "Czy lubisz kawę?",
            "subtitle": "Odpowiedź: Tak/Nie"
        },
        {
            "label": "Pytanie specjalne",
            "title": "Co lubisz? KTO – Kto? (o ludziach)",
            "subtitle": "Відповідь: I like tea."
        },
        {
            "label": "Структура",
            "title": "Wh-word + Auxiliary + Subject + Verb",
            "subtitle": "Питальне слово завжди на початку"
        }
    ]
}

{
    "title": "2. WHO — Хто? (про людей)",
    "sections": [
        {
            "label": "KTO – pytanie dotyczące osoby",
            "color": "emerald",
            "description": "<strong>Kto</strong> (who) – używane, gdy pytamy o osobę jako dodatek.",
            "examples": [
                {
                    "en": "Kogo kochasz?",
                    "ua": "Kogo kochasz?"
                },
                {
                    "en": "Kogo widziałeś?",
                    "ua": "Kogo widziałeś?"
                },
                {
                    "en": "Z kim rozmawiasz?",
                    "ua": "Z kim rozmawiasz do?"
                },
                {
                    "en": "Z kim ona pracuje?",
                    "ua": "dla kogo ona pracuje?"
                }
            ]
        },
        {
            "label": "KTO jest pytaniem do podmiotu",
            "color": "sky",
            "description": "Kiedy <strong>kto</strong> jest podmiotem, NIE używaj czasownika posiłkowego do/does/did.",
            "examples": [
                {
                    "en": "Kto tu mieszka?",
                    "ua": "Kto tu mieszka?"
                },
                {
                    "en": "Kto do Ciebie dzwonił?",
                    "ua": "Kto do Ciebie dzwonił?"
                },
                {
                    "en": "Kto chce kawa?",
                    "ua": "Kto ma ochotę na kawę?"
                },
                {
                    "en": "Kto zna odpowiedź?",
                    "ua": "Kto zna odpowiedź?"
                }
            ]
        },
        {
            "label": "KTO — czasami z różnymi",
            "color": "purple",
            "description": "Kto może być używany z różnymi napięcia.",
            "examples": [
                {
                    "en": "Kto przyjdzie na imprezę?",
                    "ua": "Kto skończył pracę?"
                },
                {
                    "en": "Who has finished the work?",
                    "ua": "Kto skończył pracę?"
                },
                {
                    "en": "Kto mi pomoże?",
                    "ua": "Kto pomoże ja?"
                }
            ],
            "note": "📌 Struktura: Kto + Pomocniczy + Podmiot + Czasownik? (lub Kto + Czasownik? w przypadku pytań na ten temat)"
        }
    ]
}

{
    "title": "3. CO — Co? (o rzeczach i informacjach)",
    "sections": [
        {
            "label": "CODX_SEG_27]]]COD – pytania ogólne",
            "color": "blue",
            "description": "<strong>Co</strong> (co) – używane do zadawania pytań o rzeczy, działania lub informacje.",
            "examples": [
                {
                    "en": "Czego chcesz?",
                    "ua": "Czego chcesz chcesz?"
                },
                {
                    "en": "Co ona powiedziała?",
                    "ua": "Co powiedziała?"
                },
                {
                    "en": "Co robisz?",
                    "ua": "Co robisz?"
                },
                {
                    "en": "Jak masz na imię?",
                    "ua": "Jak masz na imię? (Jak masz na imię?)"
                }
            ]
        },
        {
            "label": "CO + rzeczownik",
            "color": "amber",
            "description": "<strong>Co</strong> można użyć razem z rzeczownikiem dla wyjaśnienia.",
            "examples": [
                {
                    "en": "Jaki to kolor?",
                    "ua": "Jaki to kolor?"
                },
                {
                    "en": "Która jest godzina to?",
                    "ua": "O której godzinie?"
                },
                {
                    "en": "Jaki rodzaj muzyki lubisz?",
                    "ua": "Jakiego rozmiaru potrzebujesz?"
                },
                {
                    "en": "Jakiego rozmiaru potrzebujesz?",
                    "ua": "Jakiego rozmiaru potrzebujesz potrzebujesz?"
                }
            ]
        },
        {
            "label": "CO to jest pytanie na temat",
            "color": "rose",
            "description": "Kiedy <strong>co</strong> jest tematem, nie używamy zrobić/robi/zrobił.",
            "examples": [
                {
                    "en": "Co się stało?",
                    "ua": "Co się stało?"
                },
                {
                    "en": "Co sprawia, że jesteś szczęśliwy?",
                    "ua": " szczęśliwy?"
                },
                {
                    "en": "Co spowodowało problem?",
                    "ua": "Co się stało?"
                }
            ],
            "note": "📌Co się stało? — NIE Co się stało?"
        }
    ]
}

{
    "title": "4. GDZIE – Gdzie? (o miejscu)",
    "sections": [
        {
            "label": "WHERE – pytanie o miejsce",
            "color": "emerald",
            "description": "<strong>Gdzie</strong> (gdzie, gdzie) – używane do zadawania pytań o miejsce lub kierunek.",
            "examples": [
                {
                    "en": "Gdzie mieszkasz?",
                    "ua": "Gdzie mieszkasz na żywo?"
                },
                {
                    "en": "Dokąd się wybierasz?",
                    "ua": "Dokąd się wybierasz?"
                },
                {
                    "en": "Gdzie to kupiłeś?",
                    "ua": "Gdzie jest bank?"
                },
                {
                    "en": "Where is the bank?",
                    "ua": "Gdzie jest bank?"
                }
            ]
        },
        {
            "label": "GDZIE przyimki",
            "color": "sky",
            "description": "Gdzie można ich używać z przyimkami <strong>od, do, w</strong> itp.",
            "examples": [
                {
                    "en": "Skąd jesteś?",
                    "ua": "Skąd jesteś?"
                },
                {
                    "en": " Dokąd idziesz? KIEDY – Kiedy? o czasie) się wydarzy?",
                    "ua": "Куди ти збираєшся?"
                },
                {
                    "en": "Where did she come from?",
                    "ua": "Звідки вона прийшла?"
                }
            ],
            "note": "📌 Структура: Where + Auxiliary + Subject + Verb?"
        }
    ]
}

{
    "title": "5. WHEN — Коли? (про час)",
    "sections": [
        {
            "label": "WHEN — питання про час",
            "color": "blue",
            "description": "<strong>When</strong> (коли) — використовуємо для запитання про час події.",
            "examples": [
                {
                    "en": "When do you wake up?",
                    "ua": "Коли ти прокидаєшся?"
                },
                {
                    "en": "When did it happen?",
                    "ua": "Kiedy wrócisz?"
                },
                {
                    "en": "When are you leaving?",
                    "ua": "Kiedy wrócisz?"
                },
                {
                    "en": "When will you come back?",
                    "ua": "Kiedy wyjdziesz?"
                }
            ]
        },
        {
            "label": "KIEDY - różne czasy formularze",
            "color": "purple",
            "description": "Kiedy działa ze wszystkimi czasami.",
            "examples": [
                {
                    "en": "Kiedy masz urodziny?",
                    "ua": "Kiedy zaczyna się spotkanie?"
                },
                {
                    "en": "When does the meeting start?",
                    "ua": "Kiedy zaczyna się spotkanie?"
                },
                {
                    "en": "Kiedy byłeś tam?",
                    "ua": "Kiedy tam byłeś?"
                }
            ],
            "note": "📌 Odpowiedź może być konkretna (o 17:00) lub ogólna (jutro, wczoraj)"
        }
    ]
}

{
    "title": "6. DLACZEGO – Dlaczego? (o powodzie)",
    "sections": [
        {
            "label": "DLACZEGO – pytanie o powód",
            "color": "amber",
            "description": "<strong>Dlaczego</strong> (dlaczego) – używane, gdy pytamy o przyczynę lub cel.",
            "examples": [
                {
                    "en": "Dlaczego jesteś smutny?",
                    "ua": "Dlaczego jesteś smutna?"
                },
                {
                    "en": "Dlaczego odeszła?",
                    "ua": "Dlaczego odeszła?"
                },
                {
                    "en": "Dlaczego uczysz się angielskiego?",
                    "ua": "Dlaczego uczysz się angielskiego?"
                },
                {
                    "en": "Dlaczego jest to ważne?",
                    "ua": "Dlaczego jest to ważne?"
                }
            ]
        },
        {
            "label": "DLACZEGO odpowiedź zawiera PONIEWAŻ",
            "color": "rose",
            "description": "Na pytanie <strong>dlaczego</strong> zazwyczaj odpowiada się <strong>ponieważ</strong> (ponieważ).",
            "examples": [
                {
                    "en": "Dlaczego się spóźniasz? — Ponieważ spóźniłem się na autobus.",
                    "ua": "Dlaczego się spóźniłeś? — Ponieważ spóźniłem się na autobus."
                },
                {
                    "en": "Dlaczego ona jest zła? — Ponieważ zapomniał o jej urodzinach.",
                    "ua": "Dlaczego ona jest zła? — Ponieważ zapomniał o jej urodzinach."
                }
            ]
        },
        {
            "label": "DLACZEGO - sugestie i rady",
            "color": "emerald",
            "description": "Dlaczego można użyć do sugestii lub rady w budowie <strong>Dlaczego my/ty nie...?</strong>",
            "examples": [
                {
                    "en": "Dlaczego nie pójdziemy do kina?",
                    "ua": "Dlaczego nie pójdziemy do kina? film?"
                },
                {
                    "en": "Dlaczego go nie zapytasz?",
                    "ua": "Dlaczego go nie zapytasz?"
                }
            ],
            "note": "📌 Dlaczego my/ty nie...? = sugestia lub rada"
        },
        {
            "label": "DLACZEGO z czasownikami modalnymi",
            "color": "purple",
            "description": "Dlaczego można go używać z czasownikami modalnymi <strong>(powinno, może, mogłoby, byłoby, musi)</strong>, aby zapytać o powód zobowiązania, możliwości lub warunku.",
            "examples": [
                {
                    "en": "Dlaczego powinienem wierzyć ",
                    "ua": "Dlaczego miałbym ci wierzyć?"
                },
                {
                    "en": "Dlaczego ona by to zrobiła?",
                    "ua": "Dlaczego nie możemy zostać dłużej?"
                },
                {
                    "en": "Why can't we stay longer?",
                    "ua": "Dlaczego nie możemy zostać dłużej?"
                },
                {
                    "en": "Dlaczego musisz wyjechać teraz?",
                    "ua": "Dlaczego musisz teraz iść?"
                }
            ],
            "note": "📌 Struktura: Dlaczego + Czasownik modalny + Podmiot + Czasownik główny?"
        }
    ]
}

{
    "title": "7. JAK? (o metodzie i stopniu)",
    "sections": [
        {
            "label": "JAK to pytanie o metodę",
            "color": "blue",
            "description": "<strong>How</strong> (як) — використовуємо для запитання про спосіб, метод або стан.",
            "examples": [
                {
                    "en": "How do you go to work?",
                    "ua": "Як ти їдеш на роботу?"
                },
                {
                    "en": "How does it work?",
                    "ua": "Як це працює?"
                },
                {
                    "en": "How are you?",
                    "ua": "Jak się masz? Jak się masz?) Ty?"
                },
                {
                    "en": "How did you learn English?",
                    "ua": "Як ти вивчив англійську?"
                }
            ]
        },
        {
            "label": "HOW + прикметник/прислівник",
            "color": "purple",
            "description": "<strong>How</strong> комбінується з прикметниками для запитання про ступінь, кількість, відстань.",
            "examples": [
                {
                    "en": "How old are you?",
                    "ua": " Ile masz lat? wziąć?"
                },
                {
                    "en": "How tall is he?",
                    "ua": "Якого він зросту?"
                },
                {
                    "en": "How far is the station?",
                    "ua": "Як далеко станція?"
                },
                {
                    "en": "How long does it take?",
                    "ua": "Jak długo to zajmuje?"
                }
            ]
        },
        {
            "label": "ILE / JAK DUŻO",
            "color": "emerald",
            "description": "<strong>Ile</strong> (niepoliczalne) / <strong>Ile</strong> (policzalne) - w przypadku pytań o ilość.",
            "examples": [
                {
                    "en": "Ile to jest to?",
                    "ua": "Ile to kosztuje?"
                },
                {
                    "en": "Ile masz książek?",
                    "ua": "Ile mamy czasu?"
                },
                {
                    "en": "How much time do we have?",
                    "ua": "Ile osób przyjdzie?"
                },
                {
                    "en": "How many people are coming?",
                    "ua": "Ile osób przyjdzie nadchodzi?"
                }
            ],
            "note": "📌 Ile – z rzeczownikami niepoliczalnymi, Ile – z policzalnymi"
        }
    ]
}

{
    "title": "8. Tabela porównawcza słów pytających",
    "intro": "Główne słowa pytające i ich znaczenie:",
    "rows": [
        {
            "en": "WHO",
            "ua": "Kto? Kto?",
            "note": "O ludziach — kim ona jest? Kogo widziałeś?"
        },
        {
            "en": "CO",
            "ua": "Co? Które?",
            "note": "O rzeczach, informacjach — czego chcesz? O której godzinie?"
        },
        {
            "en": "GDZIE",
            "ua": "Gdzie? Gdzie? Skąd jesteś?",
            "note": "O miejscu — Gdzie mieszkasz? Skąd?"
        },
        {
            "en": "KIEDY",
            "ua": "Kiedy?",
            "note": "O czasie – Kiedy to się stało? Kiedy przyjedziesz?"
        },
        {
            "en": "DLACZEGO",
            "ua": "Dlaczego?",
            "note": "O powodzie — Dlaczego się spóźniasz? → Ponieważ..."
        },
        {
            "en": "JAK",
            "ua": "Jak? Jak? ",
            "note": "O metodzie — Jak to zrobić? Ile lat? Ile?"
        }
    ],
    "warning": "📌 Struktura: <strong>W-słowo + Pomocniczy + Podmiot + Czasownik + ...?</strong>"
}

{
    "title": "9. Struktura pytań Wh",
    "sections": [
        {
            "label": "Struktura standardowa",
            "color": "emerald",
            "description": "Ogólny wzór dla większości pytań Wh:",
            "examples": [
                {
                    "en": "Słowo-wh + pomocnicze + podmiot + czasownik główny + ...?",
                    "ua": "Słowo pytające + pomocnicze + podmiot + czasownik + ...?"
                },
                {
                    "en": "Czego chcesz?",
                    "ua": "Czego chcesz?"
                },
                {
                    "en": "Dokąd ona poszła? zrobić/does/did:",
                    "ua": "Куди (did) вона (go) пішла?"
                }
            ]
        },
        {
            "label": "Питання до підмета",
            "color": "sky",
            "description": "Коли питальне слово є підметом, НЕ використовуємо do/does/did:",
            "examples": [
                {
                    "en": "Kto tu mieszka? (NIE: Kto tu mieszka?)",
                    "ua": "Kto tu mieszka?"
                },
                {
                    "en": "Co się stało? (Nie: co się stało?)",
                    "ua": "Що сталося?"
                }
            ],
            "note": "📌 Структура: Wh-word (subject) + Verb + ...?"
        },
        {
            "label": "З дієсловом TO BE",
            "color": "amber",
            "description": "З to be робимо інверсію без do/does/did:",
            "examples": [
                {
                    "en": " Gdzie jesteś? ...?",
                    "ua": "Де ти?"
                },
                {
                    "en": "Who is she?",
                    "ua": "Хто вона?"
                },
                {
                    "en": "What is your name?",
                    "ua": "Як тебе звати?"
                }
            ],
            "note": "📌 Структура: Wh-word + be + Subject + ...?"
        }
    ]
}

{
    "title": "10. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Nieprawidłowa kolejność słów w pytaniu.",
            "wrong": "❌ Czego chcesz? Gdzie mieszkasz?",
            "right": " ✅ <span class="font-mono">Czego chcesz? Gdzie mieszkasz?</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie „do/does” w pytaniach tematycznych.",
            "wrong": "❌ Kto tu mieszka? Co się stało?",
            "right": "​​​​ <span class="font-mono">Kto tu mieszka? Co się stało?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Niewłaściwa forma czasownika po stronie pomocniczej.",
            "wrong": "❌ Gdzie ona mieszka? Co widziałeś?",
            "right": "​​​​ <span class="font-mono">Gdzie ona mieszka? Co zobaczyłeś?</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Pomieszanie między Ile a Ile.",
            "wrong": "❌ Ile pieniędzy? Ile osób?",
            "right": "​​​​ <span class="font-mono">Ile pieniędzy? Ile osób?</span>"
        }
    ]
}

{
    "title": "12. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwe słowo pytające",
    "select_intro": "Wybierz właściwe słowo pytające do każdego pytania.",
    "selects": [
        {
            "label": "______ masz na imię? (Kto / Co / Gdzie)",
            "prompt": "Jakie jest słowo pytające?"
        },
        {
            "label": "_____ mieszkasz? (Kiedy / Gdzie / Dlaczego)",
            "prompt": "Jakie jest słowo pytające?"
        },
        {
            "label": "_____ uczysz się angielskiego? (Jak / Dlaczego / Co)",
            "prompt": "Jakie jest słowo pytające?"
        },
        {
            "label": "_____ stary, czy jesteś? (Co/Gdzie/Jak) słowo.",
            "prompt": "Яке питальне слово?"
        }
    ],
    "options": [
        "Перший варіант",
        "Другий варіант",
        "Третій варіант"
    ],
    "input_title": "Вправа 2. Постав питання",
    "input_intro": "Утвори питання, використовуючи подане питальне слово.",
    "inputs": [
        {
            "before": "Mieszkasz w Kijowie. (Gdzie) → ",
            "after": ""
        },
        {
            "before": "Ona ma 25 lat. (Ile lat) → ",
            "after": ""
        },
        {
            "before": "Poszedł do parku. (Gdzie) → ",
            "after": ""
        },
        {
            "before": "Przybyli o 17:00. (Kiedy) → ",
            "after": ""
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w pytaniu specjalnym.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Czego chcesz?",
            "example_target": "Czego chcesz?"
        },
        {
            "original": "1. Gdzie ona mieszka?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Kto tu mieszka?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. Ile masz pieniędzy?",
            "placeholder": "Popraw błąd"
        }
    ]
}

{
    "title": "Inne tematy z działu Rodzaje zdań pytających",
    "items": [
        {
            "label": "Tak/Nie Pytania — Pytania ogólne",
