        {
            "label": "Wh-Pytania — Pytania specjalne (bieżące)",
            "current": true
        },
        {
            "label": "Pytania tematyczne — pytania do tematu",
            "current": false
        },
        {
            "label": "Pytania alternatywne – pytania alternatywne",
            "current": false
        },
        {
            "label": "Tagi pytań – pytania przekrojowe",
            "current": false
        }
    ]
}
